 ('42000000-0000-0000-0000-000000000401','32000000-0000-0000-0000-000000000004',1,$p$Comida y bebida$p$,$p$Comida y bebida$p$,'lesson',15),
 ('42000000-0000-0000-0000-000000000402','32000000-0000-0000-0000-000000000004',2,$p$Yo quiero: querer$p$,$p$Yo quiero: querer$p$,'lesson',15),
